.lead { color: var(--muted); font-size: 1.05rem; }

/* Blockquote */
blockquote {
  margin: 1rem 0;
  padding: 0.75rem 1rem;
  border-left: 4px solid var(--border);
  background: rgba(15,19,36,0.02);
  color: var(--muted);
  border-radius: 6px;
}

/* Code blocks and inline code */
pre, code {
  font-family: var(--mono);
}

code {
  background: #f3f4f6;
  padding: 0.15rem 0.35rem;
  border-radius: 6px;
  font-size: 0.95em;
  color: #0b1220;
}

pre {
  background: var(--code-bg);
  color: var(--code-text);
  padding: 1rem;
  border-radius: 8px;
  overflow: auto;
  font-size: 0.9rem;
  line-height: 1.45;
  box-shadow: 0 6px 18px rgba(2,6,23,0.08);
  margin: 1rem 0;
}

/* Tables */
table {
  width: 100%;
  border-collapse: collapse;
  margin: 1rem 0;
  font-size: 0.95rem;
}
th, td {
  padding: 0.6rem 0.75rem;
  border-bottom: 1px solid var(--border);
  text-align: left;
}
th {
  background: rgba(15,19,36,0.02);
  color: var(--muted);
  font-weight: 600;
}

