  font-size: 0.95em;
  color: #0b1220;
}

pre {
  background: var(--code-bg);
  color: var(--code-text);
  padding: 1rem;
  border-radius: 8px;
  overflow: auto;
  font-size: 0.9rem;
  line-height: 1.45;
  box-shadow: 0 6px 18px rgba(2,6,23,0.08);
  margin: 1rem 0;
}

/* Tables */
table {
  width: 100%;
  border-collapse: collapse;
  margin: 1rem 0;
  font-size: 0.95rem;
}
th, td {
  padding: 0.6rem 0.75rem;
  border-bottom: 1px solid var(--border);
  text-align: left;
}
th {
  background: rgba(15,19,36,0.02);
  color: var(--muted);
  font-weight: 600;
}

/* Buttons & links */
.btn {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.5rem 0.75rem;
  border-radius: 8px;
  border: 1px solid transparent;
  background: var(--accent);
  color: white;
  text-decoration: none;
  font-weight: 600;
  cursor: pointer;
}
.btn.secondary {
  background: transparent;
  color: var(--text);
  border-color: var(--border);
}
.btn.ghost {
  background: transparent;
  color: var(--muted);
  border-color: transparent;
}
.btn:focus {
  box-shadow: 0 0 0 4px rgba(15,98,254,0.12);
  outline: none;
}

/* Form elements */
input[type="text"], input[type="email"], textarea, select {
  width: 100%;
  padding: 0.6rem 0.75rem;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: white;
  font-size: 1rem;
}
label {
  display: block;
  margin-bottom: 0.35rem;
  color: var(--muted);
  font-size: 0.95rem;
}

/* Alerts */
.alert {
  padding: 0.75rem 1rem;
  border-radius: 8px;
  border: 1px solid transparent;
  margin: 1rem 0;
}
.alert.info { background: #eef2ff; color: #3730a3; border-color: rgba(99,102,241,0.2); }
.alert.success { background: #ecfdf5; color: #065f46; border-color: rgba(16,185,129,0.15); }
.alert.danger { background: #fff1f2; color: #7f1d1d; border-color: rgba(244,63,94,0.1); }

/* Footer */
.footer {
  margin-top: 2.5rem;
  padding-top: 1.25rem;
  border-top: 1px solid var(--border);
  color: var(--muted);
  font-size: 0.95rem;
}

/* Utilities */
.kv {
  display: grid;
  grid-template-columns: auto 1fr;
  gap: 0.5rem 1rem;
  align-items: start;
}
.center { text-align: center; }
.small { font-size: 0.875rem; color: var(--muted); }

/* Responsive adjustments */
@media (max-width: 900px) {
  .layout {
    grid-template-columns: 1fr;
  }
  .sidebar {
    position: relative;
    top: auto;
  }
  .container { padding: 1rem; }
  .header { gap: 0.5rem; }
}

/* Accessibility helpers */
.sr-only {
  position: absolute !important;
  height: 1px; width: 1px;
  overflow: hidden;
  clip: rect(1px, 1px, 1px, 1px);
  white-space: nowrap;
}

/* Focus-visible for keyboard users */
:focus:not(:focus-visible) { outline: none; box-shadow: none; }
:focus-visible {
  outline: 2px dashed var(--accent);
  outline-offset: 3px;
}

/* Misc tweaks */
a { color: var(--accent); }
a:hover { text-decoration: underline; }

/* End of stylesheet */
""".strip()

